import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { deleteStaff, getStaff, updateStaff } from "../../api/adminUserApi";
import { getAuth } from "../../utils/auth";

export default function StaffList() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);

  const { role } = getAuth();
  const isAdmin = role === "admin";

  const load = async () => {
    setLoading(true);
    try {
      const res = await getStaff();
      setUsers(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load users");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const toggleActive = async (u) => {
    try {
      await updateStaff(u._id, { isDeleted: !u.isDeleted });
      await load();
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

    const hardDelete = async (u) => {
    if (!window.confirm(`Permanently delete ${u.name}?`)) return;

    try {
        await deleteStaff(u._id);

        // instantly remove from UI without reload
        setUsers(prev => prev.filter(user => user._id !== u._id));

        alert("User deleted permanently");
    } catch (err) {
        alert(err.response?.data?.message || "Delete failed");
    }
    };

  if (!isAdmin) {
    return (
      <div className="page">
        <div className="pageHead">
          <div>
            <div className="pageTitle">Staff Management</div>
          </div>
        </div>
        <div className="card cardPad" style={{ textAlign: "center", color: "var(--text-light)" }}>Access denied</div>
      </div>
    );
  }

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Staff / Users</div>
          <div className="pageSub">Manage team members and permissions</div>
        </div>
        <div style={{ display: "flex", gap: 12 }}>
          <button onClick={load} disabled={loading} className="btn">
            {loading ? "Loading..." : "Refresh"}
          </button>
          <Link to="/admin/create-staff" style={{ textDecoration: "none" }}>
            <button className="btn btnPrimary">+ Create Staff</button>
          </Link>
        </div>
      </div>

      <div className="card" style={{ margin: "24px auto", maxWidth: "1000px", overflowX: "auto" }}>
        <table style={{ width: "100%", borderCollapse: "collapse", textAlign: "left" }}>
          <thead>
            <tr style={{ borderBottom: "2px solid var(--border)", backgroundColor: "rgba(76, 175, 80, 0.05)" }}>
              <th style={{ padding: "12px 16px", fontWeight: "600", color: "var(--text)", fontSize: "14px" }}>Name</th>
              <th style={{ padding: "12px 16px", fontWeight: "600", color: "var(--text)", fontSize: "14px" }}>Email</th>
              <th style={{ padding: "12px 16px", fontWeight: "600", color: "var(--text)", fontSize: "14px" }}>Role</th>
              <th style={{ padding: "12px 16px", fontWeight: "600", color: "var(--text)", fontSize: "14px" }}>Status</th>
              <th style={{ padding: "12px 16px", fontWeight: "600", color: "var(--text)", fontSize: "14px", width: "300px" }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {users
              .filter((u) => u.role !== "admin")
              .map((u) => (
              <tr key={u._id} style={{ borderBottom: "1px solid var(--border)" }}>
                <td style={{ padding: "12px 16px", color: "var(--text)", fontSize: "14px" }}>{u.name}</td>
                <td style={{ padding: "12px 16px", color: "var(--text)", fontSize: "14px" }}>{u.email}</td>
                <td style={{ padding: "12px 16px", color: "var(--text-light)", fontSize: "14px", fontWeight: "500" }}>
                  <span style={{ backgroundColor: "rgba(76, 175, 80, 0.1)", padding: "4px 8px", borderRadius: "4px", textTransform: "capitalize" }}>{u.role}</span>
                </td>
                <td style={{ padding: "12px 16px", fontSize: "14px" }}>
                  <span style={{ color: u.isDeleted ? "#f44336" : "#4CAF50", fontWeight: "500" }}>
                    {u.isDeleted ? "Deactivated" : "Active"}
                  </span>
                </td>
                <td style={{ padding: "12px 16px" }}>
                  <div style={{ display: "flex", gap: 8 }}>
                    <Link to={`/admin/staff/edit/${u._id}`} style={{ textDecoration: "none" }}>
                      <button className="btn" style={{ fontSize: "13px", padding: "6px 12px" }}>Edit</button>
                    </Link>
                    <button className="btn" style={{ fontSize: "13px", padding: "6px 12px" }} onClick={() => toggleActive(u)}>
                      {u.isDeleted ? "Activate" : "Deactivate"}
                    </button>
                    <button className="btn" style={{ fontSize: "13px", padding: "6px 12px", color: "#f44336" }} onClick={() => hardDelete(u)}>
                      Delete
                    </button>
                  </div>
                </td>
              </tr>
            ))}

            {users.length === 0 && !loading && (
              <tr>
                <td colSpan="5" style={{ padding: "24px 16px", textAlign: "center", color: "var(--text-light)" }}>No users found</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
